import{_ as e,o as n,c as s,ag as t}from"./chunks/framework.1N8rnUr9.js";const u=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"developer/architecture.md","filePath":"developer/architecture.md","lastUpdated":1775715475000}'),r={name:"developer/architecture.md"};function i(p,a,l,o,c,d){return n(),s("div",null,[...a[0]||(a[0]=[t(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><p>This page provides a technical overview of TubeBay&#39;s internal architecture. It is intended for developers who want to understand how the plugin is built or contribute to it.</p><h2 id="high-level-architecture" tabindex="-1">High-Level Architecture <a class="header-anchor" href="#high-level-architecture" aria-label="Permalink to &quot;High-Level Architecture&quot;">​</a></h2><p>TubeBay follows a <strong>Modern Hybrid Architecture</strong> pattern, splitting responsibilities between a dynamic React-based admin layer and a lightweight PHP backend for YouTube integration and frontend rendering.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                    WordPress Core                        │</span></span>
<span class="line"><span>├────────────────────────┬─────────────────────────────────┤</span></span>
<span class="line"><span>│     Admin (React SPA)  │       Frontend API / Player     │</span></span>
<span class="line"><span>│                        │                                 │</span></span>
<span class="line"><span>│  React 18 + TypeScript │  YouTube IFrame API             │</span></span>
<span class="line"><span>│  Tailwind CSS          │  PHP Renderers + Transients     │</span></span>
<span class="line"><span>│  Zustand State         │  WP-Cron Sync Engine            │</span></span>
<span class="line"><span>│  React Router (Hash)   │  SEO-friendly HTML              │</span></span>
<span class="line"><span>│                        │                                 │</span></span>
<span class="line"><span>│  ┌──────────────────┐  │  ┌───────────────────────────┐  │</span></span>
<span class="line"><span>│  │   REST API       │◄─┼──│   YouTube Controller      │  │</span></span>
<span class="line"><span>│  │  /tubebay/v1     │  │  │   Library Syncing         │  │</span></span>
<span class="line"><span>│  └────────┬─────────┘  │  └───────────────────────────┘  │</span></span>
<span class="line"><span>│           │            │                                 │</span></span>
<span class="line"><span>├───────────┼────────────┴─────────────────────────────────┤</span></span>
<span class="line"><span>│           ▼                                              │</span></span>
<span class="line"><span>│  ┌─────────────────┐  ┌──────────────────────────────┐   │</span></span>
<span class="line"><span>│  │  Controllers    │  │  Data Layer                  │   │</span></span>
<span class="line"><span>│  │  (API Layer)    │──│  (Channel / Video Entities)  │   │</span></span>
<span class="line"><span>│  └─────────────────┘  └──────────────────────────────┘   │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────────┘</span></span></code></pre></div><h2 id="backend-php" tabindex="-1">Backend (PHP) <a class="header-anchor" href="#backend-php" aria-label="Permalink to &quot;Backend (PHP)&quot;">​</a></h2><h3 id="directory-structure" tabindex="-1">Directory Structure <a class="header-anchor" href="#directory-structure" aria-label="Permalink to &quot;Directory Structure&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>app/</span></span>
<span class="line"><span>├── Api/             # REST API controllers</span></span>
<span class="line"><span>│   ├── ApiController.php       # Base controller</span></span>
<span class="line"><span>│   ├── YouTubeController.php   # Library sync and management</span></span>
<span class="line"><span>│   ├── SettingsController.php  # OAuth and generic settings</span></span>
<span class="line"><span>│   └── OnboardingController.php # Setup wizard logic</span></span>
<span class="line"><span>├── Core/            # Plugin initialization and hooks</span></span>
<span class="line"><span>├── Data/            # Business logic and entities</span></span>
<span class="line"><span>│   ├── Entities/    # Channel and Video models</span></span>
<span class="line"><span>│   └── Repositories/ # Persistence logic</span></span>
<span class="line"><span>├── Helper/          # Reusable utility functions</span></span>
<span class="line"><span>└── Templates/       # Frontend player template fragments</span></span></code></pre></div><h3 id="key-components" tabindex="-1">Key Components <a class="header-anchor" href="#key-components" aria-label="Permalink to &quot;Key Components&quot;">​</a></h3><ul><li><strong>YouTubeController:</strong> Handles library synchronization, mapping requests, and search queries against the local cache.</li><li><strong>Channel Entity:</strong> Encapsulates the configuration for a YouTube channel (API Key, OAuth Token) and manages the connection to the YouTube Data API.</li><li><strong>Sync Engine:</strong> A WP-Cron based background process that periodically refreshes the local video transient.</li></ul><h2 id="frontend-react-typescript" tabindex="-1">Frontend (React/TypeScript) <a class="header-anchor" href="#frontend-react-typescript" aria-label="Permalink to &quot;Frontend (React/TypeScript)&quot;">​</a></h2><h3 id="tech-stack" tabindex="-1">Tech Stack <a class="header-anchor" href="#tech-stack" aria-label="Permalink to &quot;Tech Stack&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Technology</th><th>Purpose</th></tr></thead><tbody><tr><td>React 18</td><td>UI library (via <code>@wordpress/element</code>)</td></tr><tr><td>TypeScript</td><td>Type-safe development</td></tr><tr><td>Tailwind CSS</td><td>Utility-first styling</td></tr><tr><td>Zustand</td><td>State management for the library and settings</td></tr><tr><td>Lucide React</td><td>Modern icon set</td></tr><tr><td>Vite</td><td>Production build tool and development server</td></tr></tbody></table><h3 id="state-management" tabindex="-1">State Management <a class="header-anchor" href="#state-management" aria-label="Permalink to &quot;State Management&quot;">​</a></h3><p>TubeBay uses <strong>Zustand</strong> for lightweight state management within the admin dashboard. This allows for immediate UI updates when a user maps a video or triggers a sync, without waiting for page refreshes.</p><h2 id="data-persistence" tabindex="-1">Data Persistence <a class="header-anchor" href="#data-persistence" aria-label="Permalink to &quot;Data Persistence&quot;">​</a></h2><ul><li><strong>Mappings:</strong> Stored in <code>wp_options</code> as a serialized array or in a dedicated custom table (Pro).</li><li><strong>Video Library:</strong> Cached via WordPress <strong>Transients</strong> to ensure high performance and quota safety.</li><li><strong>Auth Tokens:</strong> Stored securely in <code>wp_options</code> with restricted access.</li></ul><h2 id="build-system" tabindex="-1">Build System <a class="header-anchor" href="#build-system" aria-label="Permalink to &quot;Build System&quot;">​</a></h2><p>TubeBay uses <strong>Vite</strong> for the fastest possible development experience. The production builds are optimized into a single JS/CSS bundle that is enqueued only on the plugin&#39;s administrative pages.</p>`,19)])])}const g=e(r,[["render",i]]);export{u as __pageData,g as default};
